var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"예언은 틀리지 않는다.","JPN":"予言は絶対に外れない。","ENG":"The prophecy is never wrong.","TWN":"預言不會出錯。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"황금나무가 종말을 속삭인 순간, 그 이야기는 진실이 된다.","JPN":"黄金の木が終末をささやいた瞬間、その話は真実となる。","ENG":"Once the Golden Tree whispers of the apocalypse, it will become true.","TWN":"當黃金樹低語末日的瞬間，傳說便成為事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그 오랜 세월 끝에 낙원을 발견했을 땐, 마침내 그 진실을 거스를 방법을 찾았다고 생각했다.","JPN":"長い月日の果てに楽園を見つけた時、ついに真実覆す方法を見つけたと思った。","ENG":"When I discovered the Promised Land after all these years, I thought I had finally found a way to defy the truth.","TWN":"在漫長歲月的盡頭，當我發現樂園時，我以為終於找到反抗真相的方法。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만…","JPN":"でも……","ENG":"But...","TWN":"但…"},"stage":{"bg":"ROOT_VILLAGE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"우리가 구원을 향해 나아갈수록, 종말도 가까워진다.","JPN":"アタシたちが救援へ向かって進むほど、終末も近づいてくる。","ENG":"as we marched toward salvation, the end drew nearer.","TWN":"我們越是向著救贖前進，末日也越是臨近。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"마왕의 군세가 인류를 뿌리뽑기 위해 손아귀를 뻗쳐온다.","JPN":"魔王の軍勢が人類の根を絶やすために手を伸ばしてくる。","ENG":"The Demon Lord's army extends its reach to prune humanity off this world.","TWN":"魔王的軍隊伸出魔爪，試圖抹掉人類。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 그럼에도…","JPN":"しかし、それでも……","ENG":"And yet...","TWN":"但就算如此…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 나아가는 것을 멈출 수 없다.","JPN":"アタシは進むことをやめられない。","ENG":"I must keep pushing onward.","TWN":"我也不能停止前進。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_07","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 악마가 이곳의 존재를 알게 된 이상, 마왕이 움직이겠지.","JPN":"あの悪魔がここの存在に気付いた以上、魔王が動くはずよ。","ENG":"Now that the devil knows of this place, the Demon Lord will make her move.","TWN":"既然那個魔鬼已經知道了這裡的存在，魔王一定會有所行動。"},"stage":{"bg":"CORRIDOR_07","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그전까지 어떻게든… 나 혼자서라도 낙원문을 완성시켜야 해.","JPN":"それまでなんとか……アタシ一人だけでも楽園の門を完成させないといけないわ。","ENG":"Until then... I must complete Avalon's Gate, even if I have to do it by myself.","TWN":"在那之前，無論如何…就算只有我一個人，也要完成這樂園門。"},"stage":{"bg":"CORRIDOR_07","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"아, 오셨네요.","JPN":"あ、来ましたね。","ENG":"Oh, you're back.","TWN":"喔，您來啦。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"언제 오시나 기다리고 있었습니다, 제사장님.","JPN":"待っていましたよ、祭祀長。","ENG":"We were waiting for your return, High Priest.","TWN":"我一直在等您，祭司長。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너희들…?","JPN":"アナタたち……？","ENG":"You…?","TWN":"你們…？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"왜 아직도 여기에 있는 거야?","JPN":"どうしてまだここにいるの？","ENG":"Why are you all still here?","TWN":"為什麼還在這裡？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"그야 낙원으로 가는 길을 열기 위해서죠.","JPN":"そりゃ、楽園への道を開くためですよ。","ENG":"To open the path to the Promised Land, of course.","TWN":"當然是為了打開通往樂園的道路。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"낙원문의 연구는 제사장님이 계시지 않으면 완성할 수 없으니까요.","JPN":"楽園の門の研究は祭祀長がいないと完成できないですから。","ENG":"This research cannot be completed without you, High Priest.","TWN":"因為沒有祭司長，樂園門的研究就無法完成。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아직도 날 돕겠다는… 그런 태연한 소릴 하는 거니?","JPN":"まだアタシを手伝うって……そう言いたいの？","ENG":"How can you so calmly say... that you still wish to help me?","TWN":"你們還想要…幫我嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"무슨 일이 일어나든 저희가 해야할 일은 변치 않습니다.","JPN":"何が起ころうと、私たちのやるべきことは同じです。","ENG":"Whatever happens, the work we must do has not changed.","TWN":"無論發生什麼，我們的任務都不會改變。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"제사장님이 수백 년 동안 변함없이, 저희 선조들의 고향을 지켜주신 것처럼요.","JPN":"祭祀長が数百年の間変わらず、祖先の故郷を守ってくれたように。","ENG":"Much like how you have protected the home of our ancestors for centuries.","TWN":"就像祭司長幾百年來不變地守護著我們祖先的故鄉一樣。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너희 선조들이 쌓아온 역사를 송두리째 부정하는 존재가 지금 눈앞에 있어.","JPN":"アナタたちの祖先が築いてきた歴史を丸ごと否定する存在が今目の前にいるわ。","ENG":"I stand before you, a being who completely denies the history your ancestors have accumulated.","TWN":"現在你眼前的這個存在，徹底否定了你們祖先積累的歷史。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"악마가 어떤 존재인지… 모르지 않을 텐데?","JPN":"悪魔がどんな存在なのか……知っているでしょう？","ENG":"I am sure... that you know what a devil is.","TWN":"你應該知道魔鬼是什麼樣子的吧…？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"알고 있어요.","JPN":"わかっています。","ENG":"We do.","TWN":"我知道。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"하지만 우리의 역사는 당신과 함께한 역사이기도 합니다.","JPN":"ですが、私たちの歴史はいつもあなたと共にありました。","ENG":"But you are also part of the history we have created.","TWN":"但是我們的歷史也是與您一起的歷史。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"당신이 어떤 존재이건, 지금까지 그루터기를 이끌어왔다는 진실은 변함없어요.","JPN":"あなたがどんな存在であっても、今まで切り株を導いてきたという真実は変わりません。","ENG":"Whoever you are, it does not change the fact that you have led the Stump until now.","TWN":"無論祭司長是什麼樣的存在，至今為止您引領著我們的這一事實不會改變。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"날 돕고도, 후회하지 않을 자신 있어?","JPN":"アタシを手伝って、後悔しないと言い切れるの？","ENG":"Will you not regret helping me?","TWN":"幫助我，你有信心不會後悔嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"낙원문은 저희 길잡이들이 평생을 바쳐 길러온 나무입니다.","JPN":"楽園の門は我々導き手がずっと育ててきた木です。","ENG":"Avalon's Gate is the tree that we, pathfinders, have devoted their lives to nurturing and growing.","TWN":"這個樂園門是我們引路人用一生所培育的樹木。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"그런 나무가 열매 한 번 못 맺은 채 시들어버리면, 선조를 뵐 면목이 없죠.","JPN":"そんな木が一度も実をつけることなく枯れてしまうなんて、祖先に合わせる顔がありません。","ENG":"But if that tree withers before being able to bear fruit, we will be ashamed to face our ancestors.","TWN":"如果這顆樹連一次果實都沒結就枯萎了，那就沒臉見祖先了呢。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…그래.","JPN":"……そう。","ENG":"...I see.","TWN":"…好。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그럼 시작하자.","JPN":"じゃあ、始めましょう。","ENG":"Then, let us start.","TWN":"那就開始吧。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"으음…","JPN":"うーん……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아, 모르가나.","JPN":"あ、モルガナ。","ENG":"Oh, Morgana.","TWN":"啊，莫甘娜。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"정신이 들어요? 아픈 곳은 없고요?","JPN":"気がつきました？　痛いところはないですか？","ENG":"How are you feeling? Are you hurt anywhere?","TWN":"你醒了嗎？有沒有哪裡不舒服？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"루…?","JPN":"ルー……？","ENG":"Lugh...?","TWN":"露…？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"나… 어떻게 된 거야?","JPN":"あたし……どうなったの？","ENG":"What... happened to me?","TWN":"我…這是怎麼了？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"악마에게 공격받고 정신을 잃었어요. 멀린 씨가 치료해줬고요.","JPN":"悪魔からの攻撃を受けて気を失っていました。マーリンさんが治療してくれたんです。","ENG":"You fainted after being attacked by the devil. Merlin made you all better.","TWN":"你被魔鬼攻擊後陷入了昏迷，是梅林治好了你。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"치료라고…?","JPN":"治療……？","ENG":"Made me better...?","TWN":"治好了我…？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"앗, 벌써 일어나도 괜찮겠어요?","JPN":"あっ、もう起きて大丈夫ですか？","ENG":"Oh, shouldn't you lie down and rest?","TWN":"你不要勉強起身。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"흡!","JPN":"ふっ！","ENG":"Hmpf!","TWN":"呃！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나?!","JPN":"モルガナ！？","ENG":"Morgana?!","TWN":"莫甘娜？！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"갑자기 뭐하는 짓이에요!","JPN":"いきなり何をしてるんですか！","ENG":"What are you doing?!","TWN":"你在做什麼！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"으갸악… 아파아…","JPN":"うぎゃあっ……痛い……","ENG":"Aargh... It hurts...","TWN":"哎呀…好痛…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그야 벽에 박치기를 하면 당연히 아프죠!","JPN":"壁に頭突きなんてしたら、痛いのは当然でしょう！","ENG":"Of course it hurts when you ram your head against the wall!","TWN":"撞到牆壁當然會痛！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"나…","JPN":"あたし……","ENG":"I...","TWN":"我…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"힘을 잃은 거지?","JPN":"力を失ったんだよね？","ENG":"lost my powers, right?","TWN":"失去力量了，對吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네…?","JPN":"はい……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린한테 배웠어.","JPN":"マーリンから教えてもらった。","ENG":"Merlin told me.","TWN":"梅林教過我。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"악마에게 입은 상처를 치료할 수 있는 방법은 하나 밖에 없다고.","JPN":"悪魔から受けた傷を治療できる方法は一つしかないって。","ENG":"She said that there is only one way to treat a wound from a devil.","TWN":"只有一種方法能治癒被魔鬼傷害的傷口。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그 약초를 쓰면 상처가 낫지만…","JPN":"あの薬草を使うと傷は治るけど……","ENG":"Using that herb will heal the wound…","TWN":"用那種草藥可以治癒傷口，但…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"성자의 힘을 잃는다는 것도 알아.","JPN":"聖者の力を失うって。","ENG":"But it will also make a Helgon lose its power.","TWN":"也會失去聖者的力量。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"미안해요. 저희 멋대로 이런 결정을 해버려서.","JPN":"ごめんなさい。勝手にこんなことを決めてしまって。","ENG":"I'm sorry that we made that decision without asking you first.","TWN":"對不起，我們擅自做了這個決定。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어쩔 수 없다는 거 알아.","JPN":"仕方なかったってことはわかってるよ。","ENG":"I know that there wasn't any other way.","TWN":"我知道這是沒辦法的事。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"내가 방심해서 이렇게 된 거니까.","JPN":"あたしが油断してこうなったんだし。","ENG":"It's because I let my guard down.","TWN":"因為我的疏忽才會變成這樣。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"방심이라뇨. 그런 말하지 마요.","JPN":"油断だなんて……そんなふうに言わないでください。","ENG":"Let your guard down? Don't say that.","TWN":"別說那種話！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나는 마지막까지 주민들을 돕기 위해 최선을 다했어요. 제가 봤으니까요.","JPN":"モルガナは最後まで住民たちを助けるために頑張ったんです。私が証人です。","ENG":"Morgana, you did your best to help the villagers. I saw what you did.","TWN":"莫甘娜為了幫助居民盡了最大的努力，我親眼看見的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린은… 지금까지 내 이름을 한 번도 불러준 적이 없어.","JPN":"マーリンは……今まで一度もあたしの名前を呼んでくれなかったの。","ENG":"Merlin... has never said my name once.","TWN":"梅林…她從來沒有叫過我的名字。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그루터기를 이끄는 성자가 돼서 모두의 인정을 받으면… 언젠가 이름을 불러줄 거라 생각했어.","JPN":"切り株を導く聖者になって、みんなから認めてもらえたら……いつか名前を呼んでくれると思ってた。","ENG":"I thought she'd say it one day... if I become a Helgon that led the Stump.","TWN":"我以為成為帶領木墩的聖者，得到大家的認可，總有一天她會叫我的名字。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"하지만… 이젠 안되겠지?","JPN":"でも……もうダメだよね。","ENG":"But... I guess that's not happening, is it?","TWN":"但是…現在不可能了，對吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그건 오해예요!","JPN":"それは誤解です！","ENG":"That's not true!","TWN":"那是誤會！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그루터기에서 모르가나가 얼마나 중요한 존재인지 모르는 사람은 없어요!","JPN":"切り株でモルガナがどれほど大事な存在なのか、知らない人はいません！","ENG":"Everyone in the Stump knows how important you are!","TWN":"沒有人不知道莫甘娜在木墩裡的重要性！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"게다가 멀린 씨는 모르가나를 아주 특별하게 생각한다고요!","JPN":"それに、マーリンさんはモルガナをとても特別だと思っています！","ENG":"Even Merlin thinks of you as special!","TWN":"而且梅林對你是特別的！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린이 날 특별하게 생각하는 건, 내가 성자였기 때문이야!","JPN":"マーリンがあたしのことを特別だと思ってるのは、あたしが聖者だったからだよ！","ENG":"Merlin only thought I was special because I was a Helgon!","TWN":"梅林之所以對我特別，是因為我是聖者！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"마물의 뿔을 달고 태어난 날 길러주고 가르쳐준 것도…!","JPN":"魔物のツノを持って生まれたあたしを育てて、教育してくれたのも……！","ENG":"Taking a horned girl like me under her wing...!","TWN":"從我帶著怪物的角出生那天起，她就養育我、教導我…！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그런 날 사람들이 인정해주고 따르는 것도, 내가 성자로서 쓸모가 있었기 때문이라고!","JPN":"そんなあたしをみんなが認めてくれて従ってくれるのも、あたしが聖者として価値があったからなの！","ENG":"And even the villagers recognizing me and following me, it's all because I was useful to them as a Helgon!","TWN":"人們認可我、追隨我，也是因為我作為聖者有用！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"근데 이제 난…","JPN":"でも、もうあたしは……","ENG":"But now....","TWN":"但是現在我…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아무것도 아니잖아.","JPN":"ただの人じゃない。","ENG":"I'm nothing.","TWN":"什麼都不是了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나는 영영 동토에 갇힐 뻔한 저를 구해준 은인이예요.","JPN":"モルガナは一生凍土に閉じ込められるはずだった私を助けてくれた恩人です。","ENG":"You're the one who saved me from being trapped in the gelid lands forever, Morgana.","TWN":"莫甘娜是我的恩人，是你救了差點永遠被困在凍土中的我。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모두가 절 반역자라며 두려워할 때 먼저 손을 내밀어준 사람도 모르가나였죠.","JPN":"みんなが私を反逆者だと言い怯えていた時、先に手を差し伸べてくれたのもモルガナでした。","ENG":"When everyone called me a traitor and was afraid, you were the first to give me a hand.","TWN":"當所有人都把我當成叛徒而懼怕我的時候，第一個向我伸出援手的人也是你。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그러니까, 그런 슬픈 말은 하지마요.","JPN":"だから、そんな悲しいこと言わないでください。","ENG":"So, don't say that about yourself.","TWN":"所以，你別說那種喪氣話。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"미안. 소리 질러서.","JPN":"ごめん。大きな声出して。","ENG":"Sorry for screaming.","TWN":"抱歉，剛剛吼了你。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"약초를 구해온 건 제가 아니라 멀린 씨였어요.","JPN":"薬草を探してきたのは私じゃなくてマーリンさんでした。","ENG":"Merlin was the one who went to find the herb.","TWN":"去採藥的不是我，而是梅林祭司長。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나를 구하기 위해, 지금껏 숨겨온 정체를 드러내고 악마와 싸운 것도 멀린 씨고요.","JPN":"モルガナを助けるために、今まで隠してきた正体を明かして悪魔と戦ったのもマーリンさんです。","ENG":"She even revealed her true self and fought off the devil to save you, Morgana.","TWN":"為了救莫甘娜，暴露了自己隱藏的身份，並與魔鬼戰鬥的也是她。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"단지 이름을 불러주지 않았다고 해서, 멀린 씨에게 모르가나가 소중하지 않다는 뜻은 아닐 거예요.","JPN":"名前を呼ばなかったから、マーリンさんにとってモルガナが大切なじゃないってことではないはずですよ。","ENG":"Just because she never called you by your name, it doesn't mean that Merlin doesn't care about you.","TWN":"僅僅因為沒有叫出名字，並不表示梅林祭司長不重視你。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…정말로 그럴까?","JPN":"……本当にそうかな？","ENG":"...You really think so?","TWN":"…真的嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그럼요.","JPN":"もちろんです。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"게다가 모르가나는…","JPN":"それに、モルガナは……","ENG":"Besides...","TWN":"而且莫甘娜…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"성자의 힘에만 의존하지 않고, 뭐든 잘하는 사람이 되기 위해 노력해왔잖아요?","JPN":"聖者の力に頼らなくてもいいよう、今まで頑張ってきたんでしょう？","ENG":"You don't rely on your Helgon powers and work hard to become someone who is good at everything.","TWN":"就算不依賴聖痕，你也一直在努力成為一個什麼都能做得很好的人，不是嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그러니까, 분명 지금도 할 수 있는 일이 있을 거예요.","JPN":"だから、きっと今もできることがあるはずです。","ENG":"So, I'm sure there are still things you can do.","TWN":"所以，現在也一定有你能做的事情。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"관측형 화톳불 점화 확인…!","JPN":"観測型かがり火の点火を確認……！","ENG":"Observation bonfire ignition confirmed...!","TWN":"觀測篝火點燃確認…！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"관측 좌표 고정 및 차원도약 시스템 동기화 진행 중…!","JPN":"観測座標固定および次元跳躍システムの同期化進行中……！","ENG":"Fixing observation coordinates and proceeding with the synchronization of the space jump system...!","TWN":"觀測座標固定及次元躍遷系統同步進行中…！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"모의 계측 상황은 어떻지?","JPN":"模擬計測の状況はどう？","ENG":"How is the simulation looking to be?","TWN":"類比測量情況如何？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"모식화 단계에선 백 번의 시도 중 백 번 모두 성공적입니다.","JPN":"模式化の段階では百回のうち百回、すべて成功です。","ENG":"The model shows that all one hundred attempts were successful.","TWN":"在模型化階段，百次嘗試中百次都成功。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"정상적으로 가동될 경우, 실패 확률은 극히 낮아요.","JPN":"正常に稼働する場合、失敗する確率は極めて低いでしょう。","ENG":"Once fully in operation, the chances of failing are extremely low.","TWN":"如果正常運作，失敗率極低。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"좋아. 임상 시험은 생략해. 위상변환 수정을 1번부터 8번까지 모두 가동시켜.","JPN":"いいわ。臨床試験は省きなさい。位相変換水晶を1番から8番まですべて稼働させて。","ENG":"Very good. Skip the trial runs. Activate the phase shift crystals from 1 through 8.","TWN":"很好。跳過試驗部分，啟動1號到8號的相位轉換水晶。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"뭐지? 방금 그 진동은?!","JPN":"なんだ？　今の揺れは！？","ENG":"Huh? What is this vibration?","TWN":"呃？剛剛的震動是？！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"7번과 8번 수정에서 기능고장 확인…!","JPN":"7番と8番の水晶で機能の故障を確認……！","ENG":"Crystals 7 and 8 are having functional failures...!","TWN":"在第7和第8次水晶中確認了功能故障…！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"적철을 연소시키는 과정에서 역류가 발생했습니다…!","JPN":"赤鉄を燃焼させる途中で逆流が発生しました……！","ENG":"There has been a backflow in the Violarite combustion process!","TWN":"在燃燒赤鐵的過程中發生了逆流…！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"장치에 새어 든 역병 에너지가 저항반응을 일으킨 거야.","JPN":"装置に染み入った疫病エネルギーが抵抗反応を起こしたのね。","ENG":"The plague energy leaking into the device is creating resistance.","TWN":"滲入裝置的瘟疫能量引發了抗性反應。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"하지만 이미 오염된 수정을 다시 만들기엔…","JPN":"ですが、すでに汚染された水晶を作り直すには……","ENG":"To make another crystal to replace the corrupted one...","TWN":"但是要重新製造沒被污染的水晶…"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그래… 시간이 부족하지.","JPN":"そう……時間が足りないわ。","ENG":"No... there will not be enough time.","TWN":"是啊…時間不夠了。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_QM","text":{"KOREA":"내가 고쳐볼게.","JPN":"あたしが直してみるわ。","ENG":"I'll try to fix it.","TWN":"我來修吧。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"수정 회로의 오염된 부분을 찾아내면, 연명장치로 복원할 수 있을 거야.","JPN":"水晶回路の汚染された部分を探し出して、延命装置で復元できるはずよ。","ENG":"If I can find the corrupted part of the crystal circuit, I'll be able to restore it with the life support device.","TWN":"如果能找到水晶回路中被污染的部分，就能用續命裝置恢復。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그리고, 역병을 감지하는 건 내 특기니까.","JPN":"それに、疫病を感知するのはあたし得意だから。","ENG":"Also, detecting the plague is my specialty.","TWN":"而且，感應瘟疫是我的專長。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"모르가나 아가씨?","JPN":"モルガナお嬢様？","ENG":"Miss Morgana?","TWN":"莫甘娜小姐？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"하지만 연명장치를 사용하면…! 역병은 고스란히 아가씨의 몸으로 전가될 겁니다!","JPN":"ですが、延命装置を使うと……！　疫病はそのままお嬢様の体に転嫁されてしまいます！","ENG":"But if you use the life support device...! The plague will spread into your body!","TWN":"但是使用續命裝置的話…！瘟疫會直接傳到小姐的身體裡！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"걱정 마. 뿔 하나쯤 더 생긴다고 죽진 않으니까.","JPN":"心配しないで。ツノがもう一つできても死ぬわけじゃないから。","ENG":"Don't worry. Growing one more horn is not going to kill me.","TWN":"別擔心，多長一個角也不會死的。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그렇지, 멀린?","JPN":"そうだよね、マーリン？","ENG":"Isn't that right, Merlin?","TWN":"對吧，梅林？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"수정은 모르가나에게 맡겨. 나머진 냉각 시스템과 안전 장치를 점검해.","JPN":"水晶のことはモルガナに任せなさい。あとは冷却システムと安全装置を点検して。","ENG":"Leave the crystal to Morgana. The rest of you should check on the cooling system and failsafe mechanism.","TWN":"水晶交給莫甘娜。剩下人檢查冷卻系統和安全裝置。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"알겠습니다…!","JPN":"わかりました……！","ENG":"Yes, ma'am...!","TWN":"明白…！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"방어진지를 구축해! 모든 방벽의 상태를 점검해라!","JPN":"防御陣地を構築しろ！　すべての防壁の状態を点検するんだ！","ENG":"Form a defense line! Check all the barrier's conditions!","TWN":"構築防禦陣地！檢查所有屏障的狀態！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"곧 마왕군이 온다! 서둘러!","JPN":"すぐ魔王軍がくるぞ！　急げ！","ENG":"The Demon Lord's army is approaching! Make haste!","TWN":"魔王軍馬上就來了！快點！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"대장님, 그루터기의 모든 적철이 낙원문을 가동시키기 위해 동원됐어요.","JPN":"隊長、切り株のすべての赤鉄が楽園の門を稼働させるために使われています。","ENG":"Captain, all the Violarite in the Stump is being used to activate Avalon's Gate.","TWN":"隊長，所有的赤鐵都被動員去啟動門了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"지금으로선 방벽을 가동할 동력원이 부족합니다. 낙원문의 연구를 잠시 멈추는 한이 있더라도 빌려오는 편이…","JPN":"これでは防壁を稼働させる動力源が足りません。楽園の門の研究をしばらく止めてでも借りてきた方が……","ENG":"There is not enough resource to operate the barrier. Should we go ask for some even if it means pausing the research on Avalon's Gate–","TWN":"目前沒有足夠的動力源來啟動屏障。是不是該暫時停止樂園門的研究，借用一下…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"그건 안돼! 낙원문을 가동하지 못하면 이곳을 지키는 의미도 없어진다!","JPN":"それは駄目だ！　楽園の門が稼働できないと、ここを守る意味もなくなる！","ENG":"NO! If Avalon's Gate is not activated, then there is no point in defending this place!","TWN":"那不行！如果不能啟動樂園門，守住這裡也沒有意義！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_HATE"},"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"하지만 마왕의 군세로부터 그루터기를 지키려면 방벽의 가동이…!","JPN":"ですが、魔王の軍隊から切り株を守るためには防壁の稼働が……！","ENG":"But we will need the barrier in full operation to protect the Stump from the Demon Lord's army...!","TWN":"但是要從魔王的軍隊中保護木墩，必須啟動屏障…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"제가 적철을 구해올게요.","JPN":"私が赤鉄を手に入れてきます。","ENG":"I'll go find you some Violarite.","TWN":"我去找赤鐵。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이 근방에 적철을 모을 수 있는 장소가 있나요?","JPN":"この辺りに赤鉄を集められる場所はありますか？","ENG":"Is there a place nearby where I can get some?","TWN":"這附近有可以收集赤鐵的地方嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"성자…? 당신이 우릴 도와준다고?","JPN":"聖者……？　あなたが私たちを助けるだと？","ENG":"A Helgon...? You are going to help us?","TWN":"聖者…？你要幫我們嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"북동쪽으로 반나절 거리의 수로 도시에 방벽을 가동하기에 충분한 적철이 있다.","JPN":"北東にある半日距離の水路都市に、防壁を稼働させるのに十分な赤鉄がある。","ENG":"There should be enough in the canal city, about a half-day's walk northeast.","TWN":"在東北方向半天路程的水路城市，有足夠啟動屏障的赤鐵。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"그렇다곤 해도… 적철을 얻기 위해 감당해야 할 마물의 수가 너무 많을 거야.","JPN":"だが……そこには大量の魔物がいるはずだ。","ENG":"Even if you are willing to go... there are too many monsters to face to get Violarite.","TWN":"即便如此…為了得到赤鐵，要面對的怪物數量太多了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"하지만 그게 있으면 그루터기를 지킬 시간을 벌 수 있는 거죠?","JPN":"でも、それがあれば切り株を守る時間を稼げるんですよね？","ENG":"But you'll be able to defend the Stump if you get them, right?","TWN":"但是有了它，就能爭取到保護木墩的時間，對吧？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"제가 다녀올게요. 여러분은 이곳에서 습격을 대비해주세요.","JPN":"私が行ってきます。みなさんはここで襲撃に備えてください。","ENG":"I'll be back with them. You all should prepare for their attack on here.","TWN":"我去吧，大家在這裡準備應對襲擊。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"…미안하군. 부탁하지.","JPN":"……すまないな。頼む。","ENG":"...I'm sorry, but we are counting on you.","TWN":"…抱歉，拜託了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"저 성자가… 정말로 예언에 나오는 반역자가 맞을까요?","JPN":"あの聖者が……本当に予言の中の反逆者なんでしょうか？","ENG":"Is that Helgon... really the traitor from the prophecy?","TWN":"那個聖者…不是預言中的叛徒嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"제사장님 말씀을 되새겨라.","JPN":"祭祀長の言葉を思い出せ。","ENG":"Remember the High Priest's words.","TWN":"記住祭司長的話。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"예언에 휘둘리지 말고, 눈앞에 보이는 것을 스스로 판단하는 거다.","JPN":"予言に振り回されず、目の前にあるものを自分で判断するのだ。","ENG":"Do not be swayed by prophecies, and judge for yourself what you see in front of you.","TWN":"不要被預言左右，要自己判斷眼前的事物。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"네 눈엔 저 소녀의 뒷모습이 악마에게 영혼을 팔아넘길 것처럼 보이나?","JPN":"お前の目にはあの少女の後ろ姿が悪魔に魂を売るように見えるか？","ENG":"Does that girl's back look like she will sell her soul to the devil in your eyes?","TWN":"你覺得那個少女的背影像是會把靈魂賣給魔鬼嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_LAUGH"},"R":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"…아뇨.","JPN":"……いいえ。","ENG":"...No.","TWN":"…不。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"누가 봐도 우리를 구원할 영웅이잖습니까.","JPN":"誰が見ても英雄です。","ENG":"Anyone can see that she is the hero who will save us.","TWN":"任誰看都知道，她是來拯救我們的英雄。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"해보는 거예요.","JPN":"やってみましょう。","ENG":"I have to try.","TWN":"試試看吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"혼자서도 할 수 있어요. 전 성자니까.","JPN":"一人でもやれます。私は聖者ですから。","ENG":"I can do it by myself. I'm a Helgon, after all.","TWN":"我一個人也能做到。我是聖者。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"마차…?","JPN":"馬車……？","ENG":"A carriage...?","TWN":"馬車…？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"이 늙은이를 두고 혼자 원정을 가는 겁니까?","JPN":"この老人をおいて一人で遠征ですか？","ENG":"Are you leaving for an expedition without this old man?","TWN":"呵呵…你想要丟下我這個老頭子，獨自去調查嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"키안 씨…?","JPN":"キアンさん……？","ENG":"Kian...?","TWN":"奇恩爺爺…？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"조사단 여러분들까지…","JPN":"調査団のみなさんまで……","ENG":"And the survey corps members...","TWN":"連調查團的各位也…"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"조사단은 혼자 움직이지 않습니다.","JPN":"調査団は一人では行動しません。","ENG":"The survey corps moves as one.","TWN":"調查團不會單獨行動。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"함께 가시죠. 그 많은 적철을 혼자 짊어지긴 힘들 테니까요.","JPN":"一緒に行きましょう。沢山の赤鉄を一人で運ぶのは無理でしょうから。","ENG":"We will follow you. It'll be difficult to carry all that Violarite back here yourself.","TWN":"一起走吧，獨自面對那麼多敵人會很辛苦的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…네.","JPN":"……はい。","ENG":"...Okay.","TWN":"…好的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그럼, 오늘도 잘 부탁드려요.","JPN":"じゃあ、今日もよろしくお願いします。","ENG":"Then, let's do this together.","TWN":"那麼，今天也拜託大家了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};